203	function valueFor(row: StyleRow | undefined, column: SheetColumn) {
204	  if (!row) return "";
205	  const typed = column.typedField ? row[column.typedField] : null;
206	  return typed ?? row.row_data?.[column.letter] ?? (column.legacyKey ? row.row_data?.[column.legacyKey] : "") ?? "";
