213	function fieldValue(row: StyleRow, field: FieldKey) {
214	  if (field === "sku") return row.sku;
215	  if (field === "customer") return row.customer;
216	  if (field === "licensor") return row.licensor;
217	  return row.default_vendor;
218	}
