227	function hasFieldMatch(row: StyleRow, field: FieldKey) {
228	  if (field === "sku") return Boolean(row.erp_item_id || row.style_group_id || row.plm_item_id);
229	  if (field === "customer") return Boolean(row.company_id);
230	  if (field === "licensor") return Boolean(row.public_licensor_id || row.core_licensor_id);
231	  return Boolean(row.factory_id);
232	}
