234	function manualResolutionField(row: StyleRow) {
235	  const manual = row.match_notes?.manual_resolution;
236	  if (!manual || typeof manual !== "object" || Array.isArray(manual)) return null;
237	  const field = (manual as Record<string, unknown>).field_key;
238	  return typeof field === "string" ? field : null;
239	}
240	
241	function fuzzyCandidate(row: StyleRow | undefined, field: FieldKey) {
242	  const fuzzy = row?.match_notes?.fuzzy;
243	  if (!fuzzy || typeof fuzzy !== "object" || Array.isArray(fuzzy)) return null;
244	  return (fuzzy as Record<string, unknown>)[field] ?? null;
245	}
