247	function statusFor(row: StyleRow | undefined, column: SheetColumn) {
248	  if (!row || !column.linkKind) return null;
249	  if (fuzzyCandidate(row, column.linkKind)) return "needs_review";
250	  if (hasFieldMatch(row, column.linkKind)) return "matched";
251	  return "unmatched";
252	}
