254	function buildUpdate(row: StyleRow, column: SheetColumn, value: unknown) {
255	  const nextValue = value === "" ? null : column.typedField === "discontinued" ? ["true", "yes", "1"].includes(String(value).toLowerCase()) : String(value);
256	  const rowData = { ...(row.row_data ?? {}), [column.letter]: nextValue };
257	  if (column.legacyKey) rowData[column.legacyKey] = nextValue;
258	  const payload: Partial<StyleRow> & { row_data: RowData } = { row_data: rowData };
259	  if (column.typedField) (payload[column.typedField] as unknown) = nextValue;
260	  return payload;
261	}
