263	async function fetchRows(sourceSheet: string, showAll: boolean) {
264	  const rows: StyleRow[] = [];
265	  const maxRows = showAll ? Number.POSITIVE_INFINITY : DEFAULT_ROW_LIMIT;
266	  for (let from = 0; rows.length < maxRows; from += 1000) {
267	    const to = Math.min(from + 999, maxRows - 1);
268	    const { data, error } = await (supabase as any)
269	      .from("style_tracker_rows_with_bridge")
270	      .select("*")
271	      .eq("source_sheet", sourceSheet)
272	      .order("source_row_number", { ascending: false })
273	      .range(from, to);
274	    if (error) throw error;
275	    rows.push(...((data ?? []) as StyleRow[]));
276	    if (!data || data.length < 1000) break;
277	  }
278	  return rows;
279	}
