281	async function fetchCount(sourceSheet: string) {
282	  const { count, error } = await (supabase as any)
283	    .from("style_tracker_rows_with_bridge")
284	    .select("id", { count: "exact", head: true })
285	    .eq("source_sheet", sourceSheet);
286	  if (error) throw error;
287	  return count ?? 0;
288	}
