290	async function searchCandidates(item: ReviewItem | null) {
291	  if (!item) return [] as LinkCandidate[];
292	  const fuzzy = await (supabase as any).rpc("search_style_tracker_link_candidates", {
293	    p_field_key: item.fieldKey,
294	    p_query: item.rawValue,
295	    p_limit: 8,
296	    p_match_mode: "fuzzy",
297	  });
298	  if (fuzzy.error) throw fuzzy.error;
299	  if (fuzzy.data?.length) return fuzzy.data as LinkCandidate[];
300	  if (item.fieldKey === "sku") return [];
301	  const all = await (supabase as any).rpc("search_style_tracker_link_candidates", {
302	    p_field_key: item.fieldKey,
303	    p_query: item.rawValue,
304	    p_limit: 500,
305	    p_match_mode: "all",
306	  });
307	  if (all.error) throw all.error;
308	  return (all.data ?? []) as LinkCandidate[];
309	}
